class TweetCounts {
    private Map<String, Map<Integer, Integer>> tweetMap;

    public TweetCounts() {
        tweetMap = new HashMap<>();
    }

    public void recordTweet(String tweetName, int time) {
        if (!tweetMap.containsKey(tweetName)) {
            tweetMap.put(tweetName, new HashMap<>());
        }
        tweetMap.get(tweetName).put(time, tweetMap.get(tweetName).getOrDefault(time, 0) + 1);
    }

    public List<Integer> getTweetCountsPerFrequency(String freq, String tweetName, int startTime, int endTime) {
        List<Integer> result = new ArrayList<>();
        int chunkSize;
        if (freq.equals("minute")) {
            chunkSize = 60;
        } else if (freq.equals("hour")) {
            chunkSize = 3600;
        } else {
            chunkSize = 86400;
        }
        for (int i = startTime; i <= endTime; i += chunkSize) {
            int start = i;
            int end = Math.min(i + chunkSize - 1, endTime);
            result.add(tweetMap.getOrDefault(tweetName, new HashMap<>()).getOrDefault(start, 0));
        }
        return result;
    }
}

